SELECT state, population
FROM health_metrics
WHERE population = (SELECT MAX(population) FROM health_metrics);

SELECT COUNT(*)
FROM health_interventions
WHERE status = 'planned' AND date_scheduled > DATE('now');

SELECT h.state, h.year, h.overdose AS highest_overdose_rate
FROM health_metrics h
WHERE h.overdose = (SELECT MAX(overdose) FROM health_metrics);

SELECT full_name
FROM users
WHERE user_id IN (SELECT user_id FROM health_interventions WHERE intervention_id = 0);

SELECT AVG(waitlist) AS average_waitlist
FROM health_metrics
WHERE state = 'California' AND ethnicity = 'Asian';

SELECT year 
FROM years
WHERE start_date = (SELECT MIN(start_date) FROM years);

SELECT state, AVG(obesity) AS average_obesity
FROM health_metrics
GROUP BY state;

SELECT trend_description 
FROM trends 
WHERE trend_id = 0;

SELECT AVG(waitlist) AS avg_waitlist
FROM health_metrics
WHERE year = '2020' AND state = 'California';

SELECT *
FROM health_metrics
WHERE diabetes > (
    SELECT AVG(diabetes)
    FROM health_metrics
);

SELECT state, obesity
FROM health_metrics
WHERE obesity > (
    SELECT AVG(obesity)
    FROM health_metrics
);

SELECT intervention_description 
FROM health_interventions 
WHERE intervention_type = 'program launch' AND status = 'in progress';
